  insert: (...args: unknown[]) => ReturnType<typeof makeInsertChain>
  update: (...args: unknown[]) => ReturnType<typeof makeUpdateChain>
  batch: (queries: unknown[]) => Promise<unknown>
  transaction: (fn: (tx: MockDb) => Promise<unknown>) => Promise<unknown>
}

